body.script:
// ══════════════════════════════════════════════════
// CONFIG
// ══════════════════════════════════════════════════
const CONFIG = {
  "version": "1.0",
  "body_group": "BODY",
  "viewBox": "0 0 400 800",
  "categories": {
    "tshirt": {
      "label": "T-Shirt",
      "icon": "tshirt_icon",
      "fixed_seams": ["top_ts_dtl"],
      "exportViewBox": "80 110 240 260",
      "anchor_group": "ANCHORS",
      "junctions": {
        "A": { "anchor": "merger_point_shoulder", "coord": "x2y2" },
        "B": { "anchor": "merger_point_shoulder", "coord": "x1y1" },
        "C": { "mirror": "B" },
        "D": { "mirror": "A" }
      },
      "modules": {
        "base": {
          "label": "Torso", "required": true, "edge": "A-D", "options": [
            { "id": "top_ts_tor_reg", "label": "Regular" },
            { "id": "top_ts_tor_crp", "label": "Cropped" },
            { "id": "top_ts_tor_bag", "label": "Baggy" }
          ]
        },
        "neck": {
          "label": "Neckline", "required": true, "join": { "with": "base", "type": "PATH_JOIN" }, "edge": "C-B", "options": [
            { "id": "top_ts_nck_v", "label": "V-Neck" },
            { "id": "top_ts_nck_rnd", "label": "Round" },
            { "id": "top_ts_nck_mok", "label": "Mock Neck" }
          ]
        },
        "sleeves": {
          "label": "Sleeves", "required": true, "join": { "with": "base", "type": "FULL_JOIN", "order": "below_base" }, "edge_r": "A-B", "edge_l": "D-C", "options": [
            { "id": "top_ts_slv_set", "label": "Set-in" },
            { "id": "top_ts_slv_lon", "label": "Long" },
            { "id": "top_ts_slv_set_low", "label": "Set-in Low" }
          ]
        }
      },
      "details": [
        { "id": "top_ts_pkt", "label": "Pocket", "default": false },
        {
          "id": "shoulder_seam", "label": "Shoulder seam", "default": false, "type": "select", "options": [
            { "id": "sem_ts_shl_reg", "label": "Regular" },
            { "id": "sem_ts_shl_low", "label": "Raglan" }
          ]
        }
      ]
    },
    "pants": {
      "label": "Pants",
      "icon": "pants_icon",
      "disabled": true, // Corregido: Coma añadida y fuera de 'modules'
      "modules": {
        "base": {
          "label": "Leg", "required": true, "options": [
            { "id": "bot_pl_leg_str", "label": "Straight" },
            { "id": "bot_pl_leg_wid", "label": "Wide" },
            { "id": "bot_pl_leg_sli", "label": "Slim" }
          ]
        },
        "waist": {
          "label": "Waist", "required": false, "join": { "with": "base", "type": "PATH_JOIN" }, "options": [
            { "id": "bot_pl_wst_btn", "label": "Button" },
            { "id": "bot_pl_wst_ela", "label": "Elastic" }
          ]
        }
      },
      "details": []
    },
    "jacket": {
      "label": "Jacket",
      "icon": "jacket_icon",
      "disabled": true, // Corregido: Coma añadida y fuera de 'modules'
      "modules": {
        "base": {
          "label": "Body", "required": true, "options": [
            { "id": "top_pj_bod_std", "label": "Standard" }
          ]
        },
        "collar": {
          "label": "Collar", "required": false, "join": { "with": "base", "type": "PATH_JOIN" }, "options": [
            { "id": "top_pj_col_hig", "label": "High" },
            { "id": "top_pj_col_hoo", "label": "Hood" }
          ]
        },
        "quilting": {
          "label": "Quilting", "required": false, "join": { "type": "LAYER", "order": "above_base" }, "options": [
            { "id": "top_pj_qui_hor", "label": "Horizontal" },
            { "id": "top_pj_qui_squ", "label": "Square" },
            { "id": "top_pj_qui_dia", "label": "Diamond" }
          ]
        }
      },
      "details": []
    }
  }
};


// ══════════════════════════════════════════════════
// EMBEDDED ASSETS (not accessible to end user)
// ══════════════════════════════════════════════════
const EMBEDDED_SVG = `

























































































































`;

// ══════════════════════════════════════════════════
// STATE
// ══════════════════════════════════════════════════
let currentStep = 0;
let selectedCategory = null;
let totalAssetsSVG = null;
let selections = {};    // { moduleKey: optionId | 'none' }
let detailStates = {};  // { detailId: bool }

const logEl = document.getElementById('log');
function log(m,t='info'){const l=document.createElement('div');l.className=t;l.textContent=m;logEl.appendChild(l);logEl.scrollTop=logEl.scrollHeight}

// ══════════════════════════════════════════════════
// NAVIGATION
// ══════════════════════════════════════════════════
const track = document.getElementById('stepsTrack');
const dots = document.querySelectorAll('.step-dot');
const btnBack = document.getElementById('btnBack');
const btnNext = document.getElementById('btnNext');

function goStep(n) {
    currentStep = n;
    track.style.transform = `translateX(-${n * 33.333}%)`;
    dots.forEach((d,i) => { d.className = 'step-dot' + (i < n ? ' done' : i === n ? ' active' : ''); });
    btnBack.style.display = n > 0 ? '' : 'none';

    if (n === 0) { btnNext.textContent = 'Next'; btnNext.disabled = !selectedCategory || !totalAssetsSVG; }
    else if (n === 1) { btnNext.textContent = 'Next'; btnNext.disabled = false; }
    else if (n === 2) { btnNext.textContent = 'Generate'; btnNext.disabled = false; }
}

btnBack.addEventListener('click', () => { if (currentStep > 0) goStep(currentStep - 1); });
btnNext.addEventListener('click', () => {
    if (currentStep < 2) { goStep(currentStep + 1); if (currentStep === 1) buildStep1(); if (currentStep === 2) buildStep2(); }
    else { generate(); if(window.innerWidth<=800) closeSidebar(); }
});

// ══════════════════════════════════════════════════
// STEP 0 — Category + Upload
// ══════════════════════════════════════════════════
const GARMENT_ICONS = {
    tshirt_icon: ``,
    pants_icon: ``,
    jacket_icon: ``
};

const catGrid = document.getElementById('catGrid');

Object.entries(CONFIG.categories).forEach(([key, cat]) => {
    const card = document.createElement('div');
    card.className = 'cat-card';

    // Si está deshabilitada
    if (cat.disabled) {
        card.classList.add('disabled');
    } else {
        card.addEventListener('click', () => {
            catGrid.querySelectorAll('.cat-card').forEach(c => c.classList.remove('selected'));
            card.classList.add('selected');
            selectedCategory = key;
            selections = {};
            detailStates = {};

            const mods = cat.modules;
            Object.entries(mods).forEach(([mk, mod]) => {
                if (mod.required) selections[mk] = mod.options[0].id;
                else selections[mk] = 'none';
            });

            cat.details.forEach(d => detailStates[d.id] = d.default || false);

            checkStep0();
        });
    }

    const iconSvg = GARMENT_ICONS[cat.icon] || `${cat.icon}`;
    card.innerHTML = `

${iconSvg}

${cat.label}
    `;

    catGrid.appendChild(card);
});


// File upload
const dropZone = document.getElementById('dropZone');
const fileInput = document.getElementById('fileInput');
dropZone.addEventListener('click', () => fileInput.click());
dropZone.addEventListener('dragover', e => { e.preventDefault(); dropZone.style.borderColor = 'var(--blue)'; });
dropZone.addEventListener('dragleave', () => { dropZone.style.borderColor = ''; });
dropZone.addEventListener('drop', e => { e.preventDefault(); dropZone.style.borderColor=''; if(e.dataTransfer.files.length) loadFile(e.dataTransfer.files[0]); });
fileInput.addEventListener('change', e => { if(e.target.files.length) loadFile(e.target.files[0]); });

function loadFile(file) {
    const r = new FileReader();
    r.onload = ev => {
        totalAssetsSVG = new DOMParser().parseFromString(ev.target.result, 'image/svg+xml');
        dropZone.classList.add('ok');
        const badge = document.getElementById('fileBadge');
        badge.innerHTML = `✅ ${file.name}`;
        badge.style.display = 'block';
        checkStep0();
    };
    r.readAsText(file);
}

function checkStep0() { btnNext.disabled = !(selectedCategory && totalAssetsSVG); }

// ══════════════════════════════════════════════════
// STEP 1 — Modules (dynamic from config)
// ══════════════════════════════════════════════════
function buildStep1() {
    const container = document.getElementById('modulesContainer');
    container.innerHTML = '';
    if (!selectedCategory) return;
    const cat = CONFIG.categories[selectedCategory];

    Object.entries(cat.modules).forEach(([moduleKey, mod]) => {
        const sec = document.createElement('div');
        sec.innerHTML = `
${mod.label}${mod.required ? '' : ' (optional)'}`;

        const scroll = document.createElement('div');
        scroll.className = 'opt-scroll';

        // "None" option for non-required
        if (!mod.required) {
            const none = document.createElement('div');
            none.className = 'opt-card none-card' + (selections[moduleKey] === 'none' ? ' selected' : '');
            none.innerHTML = `
—
None`;
            none.addEventListener('click', () => { selectOption(moduleKey, 'none', scroll); });
            scroll.appendChild(none);
        }

        mod.options.forEach(opt => {
            const card = document.createElement('div');
            card.className = 'opt-card' + (selections[moduleKey] === opt.id ? ' selected' : '');
            // short code for mini preview
            const shortLabel = opt.label.slice(0, 3).toUpperCase();
            card.innerHTML = `
${shortLabel}
${opt.label}`;
            card.addEventListener('click', () => { selectOption(moduleKey, opt.id, scroll); });
            scroll.appendChild(card);
        });

        sec.appendChild(scroll);
        container.appendChild(sec);
    });
}

function selectOption(moduleKey, optId, scrollContainer) {
    selections[moduleKey] = optId;
    scrollContainer.querySelectorAll('.opt-card').forEach(c => c.classList.remove('selected'));
    // Find and select the right card
    const cards = scrollContainer.querySelectorAll('.opt-card');
    const cat = CONFIG.categories[selectedCategory];
    const mod = cat.modules[moduleKey];
    let idx = 0;
    if (!mod.required) {
        if (optId === 'none') cards[0].classList.add('selected');
        idx = 1;
    }
    mod.options.forEach((opt, i) => {
        if (opt.id === optId) cards[i + idx].classList.add('selected');
    });
}

// ══════════════════════════════════════════════════
// STEP 2 — Details (dynamic from config)
// ══════════════════════════════════════════════════
function buildStep2() {
    const container = document.getElementById('detailToggles');
    container.innerHTML = '';
    if (!selectedCategory) return;
    const cat = CONFIG.categories[selectedCategory];

    cat.details.forEach(det => {
        if (det.type === 'select') {
            // Select-type detail: None / Option1 / Option2
            const label = document.createElement('div');
            label.className = 'sec-label';
            label.textContent = det.label;
            container.appendChild(label);

            const scroll = document.createElement('div');
            scroll.className = 'opt-scroll';

            // "None" option
            const noneCard = document.createElement('div');
            noneCard.className = 'opt-card none-card' + (!detailStates[det.id] || detailStates[det.id] === 'none' ? ' selected' : '');
            noneCard.innerHTML = `
—
None`;
            noneCard.addEventListener('click', () => {
                detailStates[det.id] = 'none';
                scroll.querySelectorAll('.opt-card').forEach(c => c.classList.remove('selected'));
                noneCard.classList.add('selected');
            });
            scroll.appendChild(noneCard);

            det.options.forEach(opt => {
                const card = document.createElement('div');
                card.className = 'opt-card' + (detailStates[det.id] === opt.id ? ' selected' : '');
                const shortLabel = opt.label.slice(0, 3).toUpperCase();
                card.innerHTML = `
${shortLabel}
${opt.label}`;
                card.addEventListener('click', () => {
                    detailStates[det.id] = opt.id;
                    scroll.querySelectorAll('.opt-card').forEach(c => c.classList.remove('selected'));
                    card.classList.add('selected');
                });
                scroll.appendChild(card);
            });

            container.appendChild(scroll);
        } else {
            // Toggle-type detail: on/off
            const row = document.createElement('div');
            row.className = 'tog-row';
            const tog = document.createElement('div');
            tog.className = 'tog' + (detailStates[det.id] ? ' on' : '');
            tog.addEventListener('click', () => { tog.classList.toggle('on'); detailStates[det.id] = tog.classList.contains('on'); });

            row.innerHTML = `${det.label}`;
            row.appendChild(tog);
            container.appendChild(row);
        }
    });
}

// ══════════════════════════════════════════════════
// ENGINE (preserved from v12 — with fixed parseNums)
// ══════════════════════════════════════════════════
function extractGroup(groupId) {
    if (!totalAssetsSVG) return null;
    const grpId = groupId + '_GRP';
    const group = totalAssetsSVG.getElementById(grpId);
    if (!group) { log('⚠️ "'+grpId+'" not found','warn'); return null; }
    const main=[], seams=[], details=[];
    group.querySelectorAll('path,polyline,polygon,line').forEach(el => {
        const id=el.getAttribute('id')||'', tag=el.tagName.toLowerCase();
        const shape = { tag, id };
        if (tag==='path') shape.d=el.getAttribute('d');
        else if (tag==='polyline'||tag==='polygon') shape.points=el.getAttribute('points');
        else if (tag==='line') { shape.x1=el.getAttribute('x1'); shape.y1=el.getAttribute('y1'); shape.x2=el.getAttribute('x2'); shape.y2=el.getAttribute('y2'); }
        if (id.startsWith('sem_')) seams.push(shape);
        else if (id.startsWith('dtl_')) details.push(shape);
        else main.push(shape);
    });
    return { main, seams, details };
}

// Convert any shape (polyline, line, path) to a path d string
function shapeToD(shape) {
    if (shape.d) return shape.d;
    if (shape.points) {
        const pts = parseNums(shape.points);
        if (pts.length < 4) return null;
        let d = `M${pts[0]},${pts[1]}`;
        for (let i = 2; i < pts.length; i += 2) d += ` L${pts[i]},${pts[i+1]}`;
        return d;
    }
    if (shape.x1 != null) return `M${shape.x1},${shape.y1} L${shape.x2},${shape.y2}`;
    return null;
}

// Get endpoints from any shape
function shapeEndpoints(shape) {
    const d = shapeToD(shape);
    return d ? getEndpoints(d) : null;
}

// Smart reverse: uses complex reverse for curves, simple for lines
function reverseAnyD(d) {
    return /[CcSsQq]/.test(d) ? reverseComplexPath(d) : reverseLinePath(d);
}

// ═══ READ ANCHOR JUNCTIONS FROM SVG ═══
function readJunctions(cat) {
    if (!totalAssetsSVG || !cat.junctions) return null;
    const jDef = cat.junctions;
    const center = 200; // center X of the viewBox
    const pts = {};

    // Read anchor-based junctions
    for (const [name, def] of Object.entries(jDef)) {
        if (def.anchor) {
            const el = totalAssetsSVG.getElementById(def.anchor);
            if (!el) { log(`⚠️ Anchor "${def.anchor}" not found`,'warn'); continue; }
            if (def.coord === 'x1y1') pts[name] = { x: parseFloat(el.getAttribute('x1')), y: parseFloat(el.getAttribute('y1')) };
            else if (def.coord === 'x2y2') pts[name] = { x: parseFloat(el.getAttribute('x2')), y: parseFloat(el.getAttribute('y2')) };
        }
    }

    // Resolve mirrors (reflect across center X)
    for (const [name, def] of Object.entries(jDef)) {
        if (def.mirror && pts[def.mirror]) {
            const src = pts[def.mirror];
            pts[name] = { x: center + (center - src.x), y: src.y };
        }
    }

    // Log
    for (const [name, pt] of Object.entries(pts)) {
        log(`  Junction ${name}: (${pt.x.toFixed(1)}, ${pt.y.toFixed(1)})`,'info');
    }

    return pts;
}

// ═══ CLASSIFY COMPONENT: which junction is each endpoint nearest to? ═══
function classifyEndpoints(shape, junctions, tol) {
    const d = shapeToD(shape);
    if (!d) return null;
    const ep = getEndpoints(d);
    if (!ep) return null;

    const dist = (a, b) => Math.sqrt((a.x - b.x) ** 2 + (a.y - b.y) ** 2);
    const nearest = (pt) => {
        let best = null, bestD = Infinity;
        for (const [name, jpt] of Object.entries(junctions)) {
            const dd = dist(pt, jpt);
            if (dd < bestD) { bestD = dd; best = name; }
        }
        return bestD < tol ? best : null;
    };

    return { d, start: ep.start, end: ep.end, startJ: nearest(ep.start), endJ: nearest(ep.end) };
}

// ═══ 4-COMPONENT ANCHOR-DRIVEN CIRCUIT MERGE ═══
// Circuit is always: A → D → C → B → A (clockwise)
// Each component fills one edge of the circuit
function mergeCircuit(torsoShape, neckShape, slvRShape, slvLShape, junctions) {
    if (!junctions || !junctions.A || !junctions.B || !junctions.C || !junctions.D) {
        log('  ❌ Missing junctions for circuit merge','err');
        return null;
    }

    const TOL = 15; // tolerance for matching endpoints to junctions
    const stripM = d => d.replace(/^M[^A-DF-Za-df-z]*/, '').replace(/Z\s*$/i, '').trim();
    const stripZ = d => d.replace(/Z\s*$/i, '').trim();

    // Circuit edges in order: A→D, D→C, C→B, B→A
    const circuit = [
        { from: 'A', to: 'D', label: 'torso' },
        { from: 'D', to: 'C', label: 'slvL' },
        { from: 'C', to: 'B', label: 'neck' },
        { from: 'B', to: 'A', label: 'slvR' },
    ];

    // Classify all components
    const components = [
        { shape: torsoShape, name: 'TOR' },
        { shape: neckShape, name: 'NCK' },
        { shape: slvRShape, name: 'SLV_R' },
        { shape: slvLShape, name: 'SLV_L' },
    ];

    for (const c of components) {
        const info = classifyEndpoints(c.shape, junctions, TOL);
        if (!info) { log(`  ❌ Can't classify ${c.name}`,'err'); return null; }
        Object.assign(c, info);
        log(`  ${c.name}: (${info.start.x.toFixed(1)},${info.start.y.toFixed(1)}) [${info.startJ||'?'}] → (${info.end.x.toFixed(1)},${info.end.y.toFixed(1)}) [${info.endJ||'?'}]`,'info');
    }

    // For each circuit edge, find which component fills it
    let result = '';
    let chain = [];

    for (let i = 0; i < circuit.length; i++) {
        const edge = circuit[i];
        // Find component whose endpoints match this edge (fwd or rev)
        const match = components.find(c => !c.used &&
            ((c.startJ === edge.from && c.endJ === edge.to) ||
             (c.startJ === edge.to && c.endJ === edge.from)));

        if (!match) {
            log(`  ❌ No component for edge ${edge.from}→${edge.to}`,'err');
            return null;
        }

        const fwd = (match.startJ === edge.from && match.endJ === edge.to);
        match.used = true;

        if (i === 0) {
            // First segment: keep M
            result = fwd ? stripZ(match.d) : `M${match.end.x},${match.end.y} ` + reverseAnyD(match.d);
        } else {
            // Subsequent: strip M, append
            result += ' ' + (fwd ? stripM(match.d) : reverseAnyD(match.d));
        }
        chain.push(`${match.name}${fwd ? '→' : '←'}`);
    }

    result += ' Z';
    log(`  ✅ Circuit: ${chain.join(' → ')} → Z`,'ok');
    return result;
}

// ═══ 2-COMPONENT JOIN (torso + neck only) ═══
function joinTwo(shapeA, shapeB) {
    const dA = shapeToD(shapeA), dB = shapeToD(shapeB);
    if (!dA || !dB) return null;
    const ae = getEndpoints(dA), be = getEndpoints(dB);
    if (!ae || !be) return null;
    const TOL = 3, near = (a, b) => Math.abs(a.x - b.x) < TOL && Math.abs(a.y - b.y) < TOL;

    log(`  A: (${ae.start.x.toFixed(1)},${ae.start.y.toFixed(1)})→(${ae.end.x.toFixed(1)},${ae.end.y.toFixed(1)})`,'info');
    log(`  B: (${be.start.x.toFixed(1)},${be.start.y.toFixed(1)})→(${be.end.x.toFixed(1)},${be.end.y.toFixed(1)})`,'info');

    const stripM = d => d.replace(/^M[^A-DF-Za-df-z]*/, '').replace(/Z\s*$/i, '').trim();
    const stripZ = d => d.replace(/Z\s*$/i, '').trim();

    // A.end connects to B.start
    if (near(ae.end, be.start)) {
        log('  → A fwd + B fwd + Z','ok');
        return stripZ(dA) + ' ' + stripM(dB) + ' Z';
    }
    // B.end connects to A.start
    if (near(be.end, ae.start)) {
        log('  → B fwd + A fwd + Z','ok');
        return stripZ(dB) + ' ' + stripM(dA) + ' Z';
    }
    // A.start connects to B.start → reverse A + B
    if (near(ae.start, be.start)) {
        log('  → B fwd + A rev + Z','ok');
        return stripZ(dB) + ' ' + reverseAnyD(dA) + ' Z';
    }
    // A.end connects to B.end → A + reverse B
    if (near(ae.end, be.end)) {
        log('  → A fwd + B rev + Z','ok');
        return stripZ(dA) + ' ' + reverseAnyD(dB) + ' Z';
    }
    log('  ❌ No join strategy','err');
    return null;
}

function parseNums(s) { return (s.match(/[-+]?\d*\.?\d+(?:[eE][-+]?\d+)?/g)||[]).map(parseFloat); }

function tracePathPoints(d) {
    const pts=[], cmds=d.match(/[MmLlHhVvCcSsQqTtAaZz][^MmLlHhVvCcSsQqTtAaZz]*/g);
    if(!cmds) return pts; let x=0,y=0,sx=0,sy=0;
    cmds.forEach(cmd=>{const t=cmd[0],n=parseNums(cmd.slice(1));
        switch(t){
            case'M':x=n[0];y=n[1];sx=x;sy=y;pts.push({x,y});break;case'm':x+=n[0];y+=n[1];sx=x;sy=y;pts.push({x,y});break;
            case'L':for(let i=0;i<n.length;i+=2){x=n[i];y=n[i+1];pts.push({x,y})}break;case'l':for(let i=0;i<n.length;i+=2){x+=n[i];y+=n[i+1];pts.push({x,y})}break;
            case'H':x=n[0];pts.push({x,y});break;case'h':x+=n[0];pts.push({x,y});break;
            case'V':y=n[0];pts.push({x,y});break;case'v':y+=n[0];pts.push({x,y});break;
            case'C':for(let i=0;i<n.length;i+=6){x=n[i+4];y=n[i+5];pts.push({x,y})}break;case'c':for(let i=0;i<n.length;i+=6){x+=n[i+4];y+=n[i+5];pts.push({x,y})}break;
            case'S':for(let i=0;i<n.length;i+=4){x=n[i+2];y=n[i+3];pts.push({x,y})}break;case's':for(let i=0;i<n.length;i+=4){x+=n[i+2];y+=n[i+3];pts.push({x,y})}break;
            case'Q':for(let i=0;i<n.length;i+=4){x=n[i+2];y=n[i+3];pts.push({x,y})}break;case'q':for(let i=0;i<n.length;i+=4){x+=n[i+2];y+=n[i+3];pts.push({x,y})}break;
            case'Z':case'z':x=sx;y=sy;break;
        }
    }); return pts;
}
function getEndpoints(d){const p=tracePathPoints(d);return p.length<2?null:{start:p[0],end:p[p.length-1]}}

function reverseLinePath(d){return tracePathPoints(d).slice().reverse().map(p=>`L${p.x},${p.y}`).join(' ')}

function reverseComplexPath(d){
    const segs=[],cmds=d.match(/[MmLlHhVvCcSsQqTtAaZz][^MmLlHhVvCcSsQqTtAaZz]*/g);
    if(!cmds)return d;let x=0,y=0,pc2x=0,pc2y=0;
    cmds.forEach(cmd=>{const t=cmd[0],n=parseNums(cmd.slice(1));
        if(t==='M'||t==='m'){if(t==='M'){x=n[0];y=n[1]}else{x+=n[0];y+=n[1]}segs.push({type:'M',x,y});pc2x=x;pc2y=y}
        else if(t==='L'){for(let i=0;i<n.length;i+=2){segs.push({type:'L',fx:x,fy:y,x:n[i],y:n[i+1]});x=n[i];y=n[i+1]}pc2x=x;pc2y=y}
        else if(t==='l'){for(let i=0;i<n.length;i+=2){const nx=x+n[i],ny=y+n[i+1];segs.push({type:'L',fx:x,fy:y,x:nx,y:ny});x=nx;y=ny}pc2x=x;pc2y=y}
        else if(t==='C'){for(let i=0;i<n.length;i+=6){segs.push({type:'C',fx:x,fy:y,c1x:n[i],c1y:n[i+1],c2x:n[i+2],c2y:n[i+3],x:n[i+4],y:n[i+5]});pc2x=n[i+2];pc2y=n[i+3];x=n[i+4];y=n[i+5]}}
        else if(t==='c'){for(let i=0;i<n.length;i+=6){const c1x=x+n[i],c1y=y+n[i+1],c2x=x+n[i+2],c2y=y+n[i+3],nx=x+n[i+4],ny=y+n[i+5];segs.push({type:'C',fx:x,fy:y,c1x,c1y,c2x,c2y,x:nx,y:ny});pc2x=c2x;pc2y=c2y;x=nx;y=ny}}
        else if(t==='S'||t==='s'){for(let i=0;is.type!=='M').reverse().map(s=>{
        if(s.type==='L')return`L${s.fx},${s.fy}`;if(s.type==='C')return`C${s.c2x},${s.c2y},${s.c1x},${s.c1y},${s.fx},${s.fy}`;return''
    }).join(' ');
}



const NS='http://www.w3.org/2000/svg';
function mkEl(tag,a){const e=document.createElementNS(NS,tag);for(const[k,v]of Object.entries(a))if(v!=null)e.setAttribute(k,String(v));return e}
function renderSh(s,a){
    if(s.tag==='path'&&s.d)return mkEl('path',{d:s.d,...a});
    if((s.tag==='polyline'||s.tag==='polygon')&&s.points)return mkEl(s.tag,{points:s.points,...a});
    if(s.tag==='line'&&s.x1)return mkEl('line',{x1:s.x1,y1:s.y1,x2:s.x2,y2:s.y2,...a});
    return null;
}

// ══════════════════════════════════════════════════
// GENERATE (anchor-driven circuit merge)
// ══════════════════════════════════════════════════
function generate() {
    logEl.innerHTML='';log('━━━ GENERATING ━━━','info');
    const preview=document.getElementById('svg-preview');preview.innerHTML='';
    if(!totalAssetsSVG||!selectedCategory)return;

    const cat=CONFIG.categories[selectedCategory];
    const fill=document.getElementById('cFill').value;
    const stroke=document.getElementById('cStroke').value;
    const sw=parseFloat(document.getElementById('rSW').value);
    const showSeams=document.getElementById('togSeams').classList.contains('on');

    const svg=document.createElementNS(NS,'svg');svg.setAttribute('viewBox',CONFIG.viewBox);svg.setAttribute('xmlns',NS);
    const gA={fill,stroke,'stroke-width':sw,'stroke-linejoin':'round','stroke-linecap':'round'};
    const seamAttr={fill:'none',stroke,'stroke-width':Math.max(sw*0.6,0.5),'stroke-linejoin':'round','stroke-linecap':'round','stroke-dasharray':'0.75 2'};
    const dtlAttr={fill:'none',stroke,'stroke-width':Math.max(sw*0.5,0.4),'stroke-linecap':'round'};

    // Read anchor junctions
    log('Reading junctions...','info');
    const junctions = readJunctions(cat);

    // Body
    const bodyG=totalAssetsSVG.getElementById(CONFIG.body_group);
    if(bodyG){const bg=mkEl('g',{id:'layer-body'});bodyG.querySelectorAll('path').forEach(p=>bg.appendChild(mkEl('path',{d:p.getAttribute('d'),fill:'#ddd',stroke:'none'})));svg.appendChild(bg);log(`Body: ${bodyG.querySelectorAll('path').length}`,'ok')}

    const mods=cat.modules;
    const moduleKeys=Object.keys(mods);
    let allSeams=[], allDetails=[];

    // Find key modules
    const baseKey=moduleKeys.find(k=>mods[k].required);
    const neckKey=moduleKeys.find(k=>mods[k].join?.type==='PATH_JOIN');
    const sleeveKey=moduleKeys.find(k=>mods[k].join?.type==='FULL_JOIN');

    const baseId=selections[baseKey];
    const neckId=neckKey && selections[neckKey]!=='none' ? selections[neckKey] : null;
    const sleeveId=sleeveKey && selections[sleeveKey]!=='none' ? selections[sleeveKey] : null;

    if(baseId && baseId!=='none'){
        const baseData=extractGroup(baseId);
        if(!baseData){log('❌ Base not found','err');return}

        const gg=mkEl('g',{id:'layer-garment'});
        allSeams.push(...baseData.seams);
        allDetails.push(...baseData.details);

        // Extract sleeve data
        let slvData=null, slvR=null, slvL=null;
        if(sleeveId){
            slvData=extractGroup(sleeveId);
            if(slvData){
                allSeams.push(...slvData.seams);
                allDetails.push(...slvData.details);
                slvR=slvData.main.find(s=>s.id.endsWith('_r'));
                slvL=slvData.main.find(s=>s.id.endsWith('_l'));
                log(`Sleeves: R=${slvR?.id||'?'}, L=${slvL?.id||'?'}`,'info');
            }
        }

        // Extract neck data
        let neckData=null, neckShape=null;
        if(neckId){
            neckData=extractGroup(neckId);
            if(neckData){
                allSeams.push(...neckData.seams);
                allDetails.push(...neckData.details);
                // Find the actual neck shape by matching its ID to the component ID
                neckShape=neckData.main.find(s=>s.id===neckId) 
                    || neckData.main.find(s=>s.id && s.id.startsWith('top_ts_nck'))
                    || neckData.main.find(s=>s.tag==='polyline'||s.tag==='path');
                log(`Neck: ${neckShape?.id||'?'}`,'info');
            }
        }

        const baseShape=baseData.main.find(s=>s.tag==='polyline'||s.tag==='path')||baseData.main[0];

        // ═══ MERGE LOGIC ═══
        let merged=null;

        // 4-merge: anchor-driven circuit
        if(baseShape && neckShape && slvR && slvL && junctions){
            log('Attempting anchor-driven 4-component merge...','info');
            merged=mergeCircuit(baseShape, neckShape, slvR, slvL, junctions);
        }

        // 2-merge fallback: torso + neck
        if(!merged && baseShape && neckShape){
            log('Attempting 2-component merge (torso+neck)...','info');
            merged=joinTwo(baseShape, neckShape);
        }

        // Render sleeves as separate layer if not in 4-merge circuit
        if(slvData && !(merged && baseShape && neckShape && slvR && slvL && junctions)){
            const slvG=mkEl('g',{id:'layer-sleeves'});
            slvData.main.forEach(s=>{const d=shapeToD(s);if(d)slvG.appendChild(mkEl('path',{d,...gA}))});
            svg.appendChild(slvG);
        }

        if(merged){
            gg.appendChild(mkEl('path',{d:merged,...gA}));
            log('✅ Merge successful!','ok');
        } else {
            log('⚠️ Merge failed — rendering separately','warn');
            baseData.main.forEach(s=>{const d=shapeToD(s);if(d)gg.appendChild(mkEl('path',{d:d.replace(/Z\s*$/i,'').trim()+' Z',...gA}));else{const el=renderSh(s,gA);if(el)gg.appendChild(el)}});
            if(neckShape){const d=shapeToD(neckShape);if(d)gg.appendChild(mkEl('path',{d,...gA}))}
        }
        svg.appendChild(gg);
    }

    // ═══ SEAM LINES (from components) ═══
    if(showSeams && allSeams.length){
        const sg=mkEl('g',{id:'layer-seams'});
        allSeams.forEach(s=>{const el=renderSh(s,seamAttr);if(el)sg.appendChild(el)});
        svg.appendChild(sg);
        log(`Seams: ${allSeams.length}`,'ok');
    }

    // ═══ DETAIL LINES (from components — dtl_) ═══
    if(showSeams && allDetails.length){
        const dg=mkEl('g',{id:'layer-details'});
        allDetails.forEach(s=>{const el=renderSh(s,seamAttr);if(el)dg.appendChild(el)});
        svg.appendChild(dg);
        log(`Details: ${allDetails.length}`,'ok');
    }

    // ═══ FIXED SEAMS (always visible from config) ═══
    if(showSeams && cat.fixed_seams){
        cat.fixed_seams.forEach(fsId=>{
            const fsData=extractGroup(fsId);
            if(fsData){
                const fg=mkEl('g',{id:'layer-fixed-'+fsId});
                [...fsData.main,...fsData.seams,...fsData.details].forEach(s=>{
                    const el=renderSh(s,dtlAttr);if(el)fg.appendChild(el);
                });
                svg.appendChild(fg);
                log(`Fixed: ${fsId}`,'ok');
            }
        });
    }

    // ═══ CONFIG-DRIVEN DETAILS (toggleable + select) ═══
    cat.details.forEach(det=>{
        if(det.type==='select'){
            // Select-type: shoulder seams off/regular/raglan
            const selectedOpt=detailStates[det.id];
            if(!selectedOpt || selectedOpt==='none') return;
            if(!showSeams) return;
            const dd=extractGroup(selectedOpt);
            if(dd){
                const dg=mkEl('g',{id:'layer-'+det.id});
                [...dd.main,...dd.seams,...dd.details].forEach(s=>{
                    const el=renderSh(s,dtlAttr);if(el)dg.appendChild(el);
                });
                svg.appendChild(dg);
                log(`${det.label}: ${selectedOpt}`,'ok');
            }
        } else {
            // Toggle-type: on/off
            if(!detailStates[det.id])return;
            const dd=extractGroup(det.id);
            if(dd){
                const dg=mkEl('g',{id:'layer-'+det.id});
                [...dd.main,...dd.seams,...dd.details].forEach(s=>{
                    const isPkt=det.id.includes('pkt');
                    const attr=isPkt?{fill:'none',stroke,'stroke-width':sw,'stroke-linejoin':'round','stroke-linecap':'round'}:dtlAttr;
                    const el=renderSh(s,attr);if(el)dg.appendChild(el);
                });
                svg.appendChild(dg);
                log(`${det.label}: ${dd.main.length+dd.seams.length+dd.details.length}`,'ok');
            }
        }
    });

    preview.appendChild(svg);
    document.getElementById('btnDownload').style.display='';
    if(window.innerWidth<=800) document.getElementById('mobileDownload').classList.add('show');
    document.getElementById('topbarTitle').textContent=cat.label+' — Generated';
    log('━━━ DONE ━━━','ok');
}


// ── Color/slider live bindings ──
document.getElementById('togSeams').addEventListener('click', function() { this.classList.toggle('on'); });
document.getElementById('cFill').addEventListener('input',e=>document.getElementById('hFill').textContent=e.target.value);
document.getElementById('cStroke').addEventListener('input',e=>document.getElementById('hStroke').textContent=e.target.value);
document.getElementById('rSW').addEventListener('input',e=>document.getElementById('vSW').textContent=e.target.value);

// ── Download with lead capture ──
let emailCaptured = false;

document.getElementById('btnDownload').addEventListener('click', () => {
    if (!emailCaptured) {
        document.getElementById('downloadModal').style.display = 'flex';
    } else {
        triggerDownload();
    }
});

document.getElementById('leadForm').addEventListener('submit', function(e) {
    e.preventDefault();
    const formData = new FormData(this);
    fetch("/", {
        method: "POST",
        headers: { "Content-Type": "application/x-www-form-urlencoded" },
        body: new URLSearchParams(formData).toString(),
    })
    .then(() => {
        emailCaptured = true;
        document.getElementById('downloadModal').style.display = 'none';
        triggerDownload();
    })
    .catch((error) => alert("Connection error: " + error));
});

document.getElementById('skipEmail').onclick = () => {
    emailCaptured = true;
    document.getElementById('downloadModal').style.display = 'none';
    triggerDownload();
};

function triggerDownload() {
    const svg=document.querySelector('#svg-preview svg');if(!svg)return;
    // Clone SVG for export
    const clone=svg.cloneNode(true);
    // Remove body layer (reference only)
    const bodyLayer=clone.querySelector('#layer-body');
    if(bodyLayer) bodyLayer.remove();
    // Use export viewBox if defined
    const cat=CONFIG.categories[selectedCategory];
    if(cat && cat.exportViewBox) clone.setAttribute('viewBox', cat.exportViewBox);
    const s='\n'+new XMLSerializer().serializeToString(clone);
    const b=new Blob([s],{type:'image/svg+xml'}),u=URL.createObjectURL(b),a=document.createElement('a');
    a.href=u;a.download=`flatlabs_${selectedCategory}_${Date.now()}.svg`;a.click();URL.revokeObjectURL(u);
}

// --- Mobile sidebar ---
function toggleSidebar(){
    const sb=document.querySelector('.sidebar');
    const bd=document.getElementById('sidebarBackdrop');
    const dl=document.getElementById('mobileDownload');
    const isOpen=sb.classList.contains('open');
    if(isOpen){closeSidebar()}else{sb.classList.add('open');bd.classList.add('show');if(dl)dl.style.display='none'}
}
function closeSidebar(){
    document.querySelector('.sidebar').classList.remove('open');
    document.getElementById('sidebarBackdrop').classList.remove('show');
    const dl=document.getElementById('mobileDownload');
    if(dl && dl.classList.contains('show'))dl.style.display='flex';
}

// --- Init ---
totalAssetsSVG = new DOMParser().parseFromString(EMBEDDED_SVG, 'image/svg+xml');

// Auto-select T-Shirt
selectedCategory = 'tshirt';
if (catGrid) {
    const cards = catGrid.querySelectorAll('.cat-card');
    cards.forEach(c => { if(c.textContent.includes('T-Shirt')) c.click(); });
}
goStep(0);
